import React, { useState, useEffect } from "react";
import Menu from "./Menu";  // Assuming Menu.js is your main menu component
import Login from "./Login";  // Import the Login component
import Register from "./Register";  // Import the Register component
import logo from "./images/logo.png";
import { Box, CssBaseline, Typography, Button } from "@mui/material";
import { BrowserRouter as Router, Route, Routes, useNavigate } from "react-router-dom";  // Make sure you import 'useNavigate'

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const navigate = useNavigate(); // useNavigate instead of useHistory()

  useEffect(() => {
    const token = localStorage.getItem("authToken");
    if (token) {
      setIsLoggedIn(true);
    }
  }, []);

  const handleLogin = () => {
    setIsLoggedIn(true);
  };

  const handleLogout = () => {
    localStorage.removeItem("authToken");
    setIsLoggedIn(false);
    navigate("/login");  // Redirect to login page after logout
  };

  return (
    <Box
      display="flex"
      flexDirection="column"
      minHeight="100vh"
      style={{ backgroundColor: '#f1f1f1' }}
    >
      <CssBaseline />
      <Box
        display="flex"
        justifyContent="flex-start"
        alignItems="center"
        height="80px"
        backgroundColor="#e2e2e2"
        paddingLeft="20px"
      >
        <img
          src={logo}
          alt="QuickBite logo"
          style={{ width: '100px', height: 'auto' }}
        />
      </Box>

      <Routes>
        {/* Define the routing for Login and Register */}
        <Route path="/" element={isLoggedIn ? (
          <>
            <Menu />
            <Box textAlign="center" style={{ marginTop: '20px' }}>
              <Button 
                onClick={handleLogout} 
                variant="contained" 
                color="secondary"
                sx={{ backgroundColor: '#FF6F00', color: 'white', padding: '10px 20px' }}
              >
                Logout
              </Button>
            </Box>
          </>
        ) : (
          <Login onLogin={handleLogin} />
        )} />

        {/* Register route */}
        <Route path="/register" element={<Register />} />
      </Routes>

      <footer
        style={{
          marginTop: 'auto',
          padding: '20px',
          backgroundColor: '#f1f1f1',
          textAlign: 'center',
        }}
      >
        <Typography variant="body2" color="textSecondary">
          © 2025 QuickBite. All rights reserved.
        </Typography>
      </footer>
    </Box>
  );
}

export default App;
